Field -> {
  String:name
  String:fieldType
}

Query -> {
  List{T <- Field}:fields -> {}
}

UserQuery -> Query{
  fields -> {
    Field{name -> "id" fieldType -> "ID"}
    Field{name -> "name" fieldType -> "String"}
  }
}

resolve -> {
  String:fieldName
  -> fieldName ? {
    "id" -> 1
    "name" -> "Alice"
    -> none
  }
}
